using System;
using System.IO;

namespace PortableTestMachine2.Core;

/// <summary>
/// 애플리케이션 경로 관리 (설정, 로그, 엑셀 등)
/// </summary>
public static class PathManager
{
    /// <summary>기본 데이터 디렉토리</summary>
    public static string BaseDir { get; } =
        Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData), "PortableTestMachine2");

    /// <summary>설정 파일 경로</summary>
    public static string ConfigFilePath { get; } = Path.Combine(BaseDir, "config.json");

    /// <summary>엑셀 저장 디렉토리</summary>
    public static string ExcelDir { get; } = Path.Combine(BaseDir, "Excel");

    /// <summary>로그 디렉토리</summary>
    public static string LogDir { get; } = Path.Combine(BaseDir, "Log");

    /// <summary>크래시 로그 경로</summary>
    public static string CrashLogPath { get; } = Path.Combine(BaseDir, "crash.log");

    /// <summary>
    /// 필요한 디렉토리를 모두 생성
    /// </summary>
    public static void EnsureDirectories()
    {
        Directory.CreateDirectory(BaseDir);
        Directory.CreateDirectory(ExcelDir);
        Directory.CreateDirectory(LogDir);
    }

    /// <summary>
    /// 현재 시각 기반 엑셀 파일명 반환
    /// </summary>
    public static string GetExcelFileName()
    {
        var timestamp = DateTime.Now.ToString("yyyy-MM-dd_HH_mm_ss");
        return Path.Combine(ExcelDir, $"{timestamp}.xlsx");
    }
}

using System;
using System.IO;
using System.Text.Json;

namespace PortableTestMachine2.Core;

/// <summary>
/// 애플리케이션 설정 (JSON 직렬화)
/// </summary>
public class AppConfig
{
    /// <summary>파워서플라이 시리얼 포트</summary>
    public string PowerSupplyPort { get; set; } = "COM3";

    /// <summary>IO 보드 시리얼 포트</summary>
    public string IoBoardPort { get; set; } = "COM4";

    /// <summary>자동 검사 전압 (V)</summary>
    public double AutoVolt { get; set; } = 12.0;

    /// <summary>자동 검사 횟수</summary>
    public int AutoCount { get; set; } = 5;

    /// <summary>자동 정지 모드 ("CURRENT" 또는 "TIME")</summary>
    public string AutoStopMode { get; set; } = "CURRENT";

    /// <summary>자동 정지 기준값</summary>
    public double AutoStopValue { get; set; } = 0.5;

    /// <summary>수동 검사 전압 (V)</summary>
    public double ManualVolt { get; set; } = 12.0;

    private static readonly JsonSerializerOptions JsonOptions = new()
    {
        WriteIndented = true
    };

    /// <summary>
    /// 설정 파일에서 로드. 파일이 없으면 기본값 반환.
    /// </summary>
    public static AppConfig Load()
    {
        try
        {
            var path = PathManager.ConfigFilePath;
            if (!File.Exists(path))
                return new AppConfig();

            var json = File.ReadAllText(path);
            return JsonSerializer.Deserialize<AppConfig>(json, JsonOptions) ?? new AppConfig();
        }
        catch (Exception ex)
        {
            Logger.Error("설정 파일 로드 실패, 기본값 사용", ex);
            return new AppConfig();
        }
    }

    /// <summary>
    /// 설정을 JSON 파일로 저장
    /// </summary>
    public static void Save(AppConfig config)
    {
        try
        {
            PathManager.EnsureDirectories();
            var json = JsonSerializer.Serialize(config, JsonOptions);
            File.WriteAllText(PathManager.ConfigFilePath, json);
        }
        catch (Exception ex)
        {
            Logger.Error("설정 파일 저장 실패", ex);
        }
    }
}

using System;
using System.IO;

namespace PortableTestMachine2.Core;

/// <summary>
/// 스레드 안전 로거 (일별 로그 파일 + 크래시 로그)
/// </summary>
public static class Logger
{
    private static readonly object Lock = new();

    /// <summary>
    /// 정보 레벨 로그 기록
    /// </summary>
    public static void Info(string message)
    {
        WriteLog("INFO", message);
    }

    /// <summary>
    /// 에러 레벨 로그 기록
    /// </summary>
    public static void Error(string message, Exception? ex = null)
    {
        var text = ex != null ? $"{message} | {ex.GetType().Name}: {ex.Message}" : message;
        WriteLog("ERROR", text);
    }

    /// <summary>
    /// 크래시 로그 기록 (전체 스택 트레이스 포함)
    /// </summary>
    public static void WriteCrashLog(Exception ex)
    {
        try
        {
            PathManager.EnsureDirectories();
            var entry = $"[{DateTime.Now:yyyy-MM-dd HH:mm:ss}] {ex.GetType().FullName}: {ex.Message}{Environment.NewLine}{ex.StackTrace}{Environment.NewLine}{Environment.NewLine}";

            lock (Lock)
            {
                File.AppendAllText(PathManager.CrashLogPath, entry);
            }
        }
        catch
        {
            // 크래시 로그 기록 실패 시 무시 (이중 예외 방지)
        }
    }

    /// <summary>
    /// 일별 로그 파일에 메시지 기록
    /// </summary>
    private static void WriteLog(string level, string message)
    {
        try
        {
            PathManager.EnsureDirectories();
            var fileName = $"{DateTime.Now:yyyy-MM-dd}.log";
            var filePath = Path.Combine(PathManager.LogDir, fileName);
            var entry = $"[{DateTime.Now:HH:mm:ss}] [{level}] {message}{Environment.NewLine}";

            lock (Lock)
            {
                File.AppendAllText(filePath, entry);
            }
        }
        catch
        {
            // 로그 기록 실패 시 무시 (무한 재귀 방지)
        }
    }
}
